svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🔍 SVG TEST SUCCESSFUL!');
console.log('═══════════════════════════════════════');
console.log('✅ SVG loaded and script executed');
console.log('📍 SVG namespace:', document.documentElement.namespaceURI);
console.log('📍 SVG root:', document.documentElement.tagName);
console.log('📍 Number of elements:', document.querySelectorAll('*').length);
console.log('📍 Polygon exists:', !!document.querySelector('polygon'));

// Show what DOES work in SVG context
console.log('\n📌 What works in SVG:');
console.log('  ✅ console.log() works');
console.log('  ✅ DOM queries work (document.querySelector)');
console.log('  ✅ Element creation works (createElementNS)');

// Create SVG element (not HTML iframe)
try {
  var circle = document.createElementNS('http://www.w3.org/2000/svg', 'circle');
  circle.setAttribute('cx', '200');
  circle.setAttribute('cy', '100');
  circle.setAttribute('r', '30');
  circle.setAttribute('fill', 'orange');
  document.documentElement.appendChild(circle);
  console.log('  ✅ Created new circle element dynamically');
} catch(e) {
  console.error('  ❌ Element creation failed:', e.message);
}

console.log('\n❌ What does NOT work in SVG:');
console.log('  ❌ document.body (null in SVG)');
console.log('  ❌ document.createElement (use createElementNS instead)');
console.log('  ❌ Appending HTML elements (only SVG elements)');

console.log('\n⏱️ Test completed at:', new Date().toISOString());
console.log('═══════════════════════════════════════');
